import{bQ as a,aL as d,u as r,G as s}from"./chunks/framework.D06dwy5q.js";const n="/kb/assets/01-rto-rpo-dials.DgtW2n_E.png",e="/kb/assets/02-backup-restore-drill.DHKpyw9C.png",l="/kb/assets/03-geo-async-rpo.CATRJdTD.png",o="/kb/assets/04-two-sites-three-centers.BUQBoinU.png",g=JSON.parse('{"title":"第 15 讲｜高可用和容灾","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/15-高可用和容灾.md","filePath":"00.互联网与架构基础/15-高可用和容灾.md","lastUpdated":null}'),i={name:"00.互联网与架构基础/15-高可用和容灾.md"};function p(h,t,b,u,c,E){return d(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="第-15-讲-高可用和容灾" tabindex="-1">第 15 讲｜高可用和容灾 <a class="header-anchor" href="#第-15-讲-高可用和容灾" aria-label="Permalink to &quot;第 15 讲｜高可用和容灾&quot;">​</a></h1><p><strong>高可用(High Availability)</strong> 与 <strong>容灾(Disaster Recovery)</strong> 经常被一起提到,但解决的是<strong>不同层次的问题</strong>。</p><table tabindex="0"><thead><tr><th>维度</th><th>高可用</th><th>容灾</th></tr></thead><tbody><tr><td>故障范围</td><td>局部:单机、单组件、单服务</td><td>大范围:机房、城市、区域</td></tr><tr><td>应对手段</td><td>主备、集群、健康检查、自动切换</td><td>异地备份、跨地域同步、灾备站点</td></tr><tr><td>切换时间</td><td>秒级到分钟级</td><td>分钟级到小时级</td></tr><tr><td>数据完整性</td><td>通常零丢失</td><td>可能丢失少量数据</td></tr><tr><td>成本</td><td>中等</td><td>高(尤其多活)</td></tr></tbody></table><p>简言之:<strong>高可用应对&quot;小故障&quot;,容灾应对&quot;大灾难&quot;</strong>。两者都涉及备份、切换、同步、演练,但影响范围和投入完全不同。</p><p>本讲围绕容灾的核心展开:RTO/RPO 指标、备份恢复的工程要求、主备与异地备的差异、同城双活、异地双活、两地三中心、多活架构的风险。</p><h2 id="一、rto-和-rpo-容灾的两个核心指标" tabindex="-1">一、RTO 和 RPO:容灾的两个核心指标 <a class="header-anchor" href="#一、rto-和-rpo-容灾的两个核心指标" aria-label="Permalink to &quot;一、RTO 和 RPO:容灾的两个核心指标&quot;">​</a></h2><p>容灾方案设计的两个最重要指标:</p><p><img src="'+n+'" alt="RTO 和 RPO 分别衡量恢复时间和数据丢失窗口"></p><table tabindex="0"><thead><tr><th>指标</th><th>含义</th><th>衡量什么</th></tr></thead><tbody><tr><td>RTO(Recovery Time Objective)</td><td>故障后业务恢复需要多久</td><td>服务停摆时间</td></tr><tr><td>RPO(Recovery Point Objective)</td><td>故障后最多丢失多长时间的数据</td><td>数据丢失量</td></tr></tbody></table><h3 id="一个具体例子" tabindex="-1">一个具体例子 <a class="header-anchor" href="#一个具体例子" aria-label="Permalink to &quot;一个具体例子&quot;">​</a></h3><p>某系统每天凌晨 0 点做一次全量备份,上午 10 点数据库损坏:</p><ul><li>只能恢复到 0 点那份备份 → 0:00 到 10:00 的写入全部丢失,<strong>RPO ≈ 10 小时</strong></li><li>从准备机器、恢复备份到业务可用花了 2 小时 → <strong>RTO = 2 小时</strong></li></ul><h3 id="rto-和-rpo-与成本的关系" tabindex="-1">RTO 和 RPO 与成本的关系 <a class="header-anchor" href="#rto-和-rpo-与成本的关系" aria-label="Permalink to &quot;RTO 和 RPO 与成本的关系&quot;">​</a></h3><p><strong>RTO 和 RPO 越小,成本越高</strong>——这是容灾设计的铁律。</p><table tabindex="0"><thead><tr><th>RTO / RPO</th><th>方案</th><th>相对成本</th></tr></thead><tbody><tr><td>RTO 数小时 / RPO 一天</td><td>每日备份 + 故障时手工恢复</td><td>1×</td></tr><tr><td>RTO 数分钟 / RPO 数分钟</td><td>主备 + binlog 持续归档</td><td>5-10×</td></tr><tr><td>RTO 秒级 / RPO 接近零</td><td>同城双活 + 同步复制</td><td>30-50×</td></tr><tr><td>RTO 秒级 / RPO 零</td><td>异地多活 + 强一致</td><td>100×+</td></tr></tbody></table><p><strong>容灾方案设计的第一步是与业务方对齐目标</strong>:</p><ul><li>这个系统能容忍多久不可用?</li><li>能容忍丢失多少数据?</li></ul><p>根据业务实际承受能力反推架构,而不是盲目追求&quot;零 RPO 零 RTO&quot;。绝大多数业务并不需要那种级别的保障——把所有成本都堆到容灾上,反而拖垮整个系统经济性。</p><h3 id="不同业务的合理目标" tabindex="-1">不同业务的合理目标 <a class="header-anchor" href="#不同业务的合理目标" aria-label="Permalink to &quot;不同业务的合理目标&quot;">​</a></h3><table tabindex="0"><thead><tr><th>业务类型</th><th>典型 RTO</th><th>典型 RPO</th></tr></thead><tbody><tr><td>内部低频工具</td><td>数小时到一天</td><td>一天</td></tr><tr><td>一般 SaaS 业务</td><td>数十分钟</td><td>数分钟到一小时</td></tr><tr><td>电商业务(非交易)</td><td>分钟级</td><td>秒级</td></tr><tr><td>在线交易、支付</td><td>秒级</td><td>接近零</td></tr><tr><td>金融核心</td><td>秒级</td><td>零(异步丢失也不可接受)</td></tr></tbody></table><h2 id="二、备份恢复-容灾的底线" tabindex="-1">二、备份恢复:容灾的底线 <a class="header-anchor" href="#二、备份恢复-容灾的底线" aria-label="Permalink to &quot;二、备份恢复:容灾的底线&quot;">​</a></h2><p>备份是容灾的<strong>绝对底线</strong>——所有更高级的容灾形态(主备、双活、多活)都建立在备份之上。</p><p><img src="'+e+`" alt="备份必须经过恢复演练才算可靠"></p><h3 id="备份能应对的故障" tabindex="-1">备份能应对的故障 <a class="header-anchor" href="#备份能应对的故障" aria-label="Permalink to &quot;备份能应对的故障&quot;">​</a></h3><p>主备/复制能应对的故障(节点故障、机房故障),备份能应对<strong>所有故障</strong>,包括:</p><ul><li>误删数据(<code>DROP TABLE</code>、<code>DELETE</code> 无 WHERE)</li><li>应用 bug 写脏数据</li><li>勒索病毒加密数据</li><li>存储损坏</li><li>主从复制把误操作同步走了</li><li>配置错误导致数据被覆盖</li><li>安全事件后数据篡改</li></ul><p><strong>这些场景下复制完全无效</strong>(因为错误操作会被同步到所有副本),只有从历史时间点的备份才能恢复。</p><h3 id="备份不是-做了就行" tabindex="-1">备份不是&quot;做了就行&quot; <a class="header-anchor" href="#备份不是-做了就行" aria-label="Permalink to &quot;备份不是&quot;做了就行&quot;&quot;">​</a></h3><p>要保证备份真正可用,需要确认:</p><table tabindex="0"><thead><tr><th>维度</th><th>要确认什么</th></tr></thead><tbody><tr><td>频率</td><td>每小时/每天?决定 RPO 上限</td></tr><tr><td>保留周期</td><td>保留几天/几周/几个月?决定能恢复到多久之前</td></tr><tr><td>异地保存</td><td>备份必须跟源数据物理隔离</td></tr><tr><td>权限隔离</td><td>误删生产的人不能顺手删备份</td></tr><tr><td>加密</td><td>备份本身要加密,防止泄露</td></tr><tr><td>校验</td><td>定期验证备份文件完整性</td></tr><tr><td>恢复演练</td><td>备份能不能真的恢复出来</td></tr></tbody></table><h3 id="备份未演练-没有备份" tabindex="-1">&quot;备份未演练 = 没有备份&quot; <a class="header-anchor" href="#备份未演练-没有备份" aria-label="Permalink to &quot;&quot;备份未演练 = 没有备份&quot;&quot;">​</a></h3><p><strong>最容易被忽略的是恢复演练</strong>。备份文件存在 ≠ 能恢复成功。常见失效情况:</p><table tabindex="0"><thead><tr><th>失效原因</th><th>现场表现</th></tr></thead><tbody><tr><td>压缩包损坏</td><td>解压报错</td></tr><tr><td>账号权限不够</td><td>恢复时无法写入目标位置</td></tr><tr><td>数据库版本不兼容</td><td>备份是 MySQL 5.7,目标是 8.0</td></tr><tr><td>缺少 binlog</td><td>全量备份能恢复但无法基于时间点恢复</td></tr><tr><td>对象存储跨区域同步未完成</td><td>异地备份其实还没到位</td></tr><tr><td>加密 key 丢失</td><td>备份文件无法解密</td></tr><tr><td>备份文件其实是空的</td><td>备份脚本失败但没人发现</td></tr></tbody></table><p><strong>这些情况都让&quot;以为有备份&quot;变成&quot;备份用不了&quot;</strong>——真正发现问题时,损失已经无法挽回。</p><h3 id="恢复演练的标准流程" tabindex="-1">恢复演练的标准流程 <a class="header-anchor" href="#恢复演练的标准流程" aria-label="Permalink to &quot;恢复演练的标准流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 1 步:准备一套与生产隔离的目标环境</span></span>
<span class="line"><span>第 2 步:从备份系统拉取最新备份文件</span></span>
<span class="line"><span>第 3 步:在目标环境完整恢复(数据库 + 配置 + 文件)</span></span>
<span class="line"><span>第 4 步:启动应用连接恢复的数据库</span></span>
<span class="line"><span>第 5 步:跑关键业务查询,验证数据完整性</span></span>
<span class="line"><span>第 6 步:对比生产数据,确认恢复点正确</span></span>
<span class="line"><span>第 7 步:记录恢复耗时、问题、改进点</span></span></code></pre></div><p><strong>只看&quot;备份任务执行成功&quot;日志远远不够</strong>——必须真正恢复出来才算备份有效。建议频率:</p><ul><li>关键业务系统:每月一次</li><li>一般业务系统:每季度一次</li><li>边缘系统:每半年一次</li></ul><h3 id="备份的-3-2-1-原则" tabindex="-1">备份的 3-2-1 原则 <a class="header-anchor" href="#备份的-3-2-1-原则" aria-label="Permalink to &quot;备份的 3-2-1 原则&quot;">​</a></h3><p>业界经典的备份原则:</p><ul><li><strong>3</strong> 份数据副本(生产 + 2 份备份)</li><li><strong>2</strong> 种不同存储介质(磁盘 + 对象存储)</li><li><strong>1</strong> 份异地存储</li></ul><p>这个原则同时防御了硬件故障、单点存储故障、机房级灾难三类问题。</p><h2 id="三、主备与异地备" tabindex="-1">三、主备与异地备 <a class="header-anchor" href="#三、主备与异地备" aria-label="Permalink to &quot;三、主备与异地备&quot;">​</a></h2><p><img src="`+l+`" alt="异地异步复制天然有 RPO 数据窗口"></p><h3 id="各种备份形态的对比" tabindex="-1">各种备份形态的对比 <a class="header-anchor" href="#各种备份形态的对比" aria-label="Permalink to &quot;各种备份形态的对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>形态</th><th>数据同步方式</th><th>RTO</th><th>RPO</th><th>成本</th></tr></thead><tbody><tr><td>本地主备</td><td>同步/半同步复制</td><td>秒级</td><td>接近零</td><td>中</td></tr><tr><td>异地备份</td><td>定期备份传输到异地</td><td>数小时</td><td>备份间隔</td><td>低</td></tr><tr><td>异地冷备</td><td>异步复制 + 平时不运行业务</td><td>数十分钟到小时</td><td>复制延迟</td><td>中</td></tr><tr><td>异地热备</td><td>实时同步 + 持续就绪</td><td>分钟级</td><td>接近零</td><td>高</td></tr><tr><td>同城双活</td><td>同步复制 + 两边都运行</td><td>秒级</td><td>零</td><td>高</td></tr><tr><td>异地双活</td><td>异步复制 + 两边都运行</td><td>秒级</td><td>秒级</td><td>极高</td></tr></tbody></table><h3 id="异地备的两个核心问题" tabindex="-1">异地备的两个核心问题 <a class="header-anchor" href="#异地备的两个核心问题" aria-label="Permalink to &quot;异地备的两个核心问题&quot;">​</a></h3><p><strong>数据怎么过去</strong>和<strong>入口怎么切过去</strong>——这两个问题决定异地备的实际效果。</p><table tabindex="0"><thead><tr><th>问题</th><th>影响</th></tr></thead><tbody><tr><td>数据同步慢</td><td>RPO 大,可能丢失大量数据</td></tr><tr><td>入口切换慢</td><td>RTO 长,业务停摆时间长</td></tr><tr><td>数据同步延迟监控</td><td>不监控就不知道实际 RPO</td></tr><tr><td>入口切换流程未演练</td><td>真出事时切不过去</td></tr></tbody></table><h3 id="异地异步复制的-rpo-代价" tabindex="-1">异地异步复制的 RPO 代价 <a class="header-anchor" href="#异地异步复制的-rpo-代价" aria-label="Permalink to &quot;异地异步复制的 RPO 代价&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>场景:数据库异步复制到异地机房</span></span>
<span class="line"><span>14:00:00 主站故障,业务转移到异地</span></span>
<span class="line"><span>14:00:00 异地数据落后主站 3 分钟</span></span>
<span class="line"><span>14:00:00 主站 13:57-14:00 的写入,异地没有</span></span>
<span class="line"><span></span></span>
<span class="line"><span>后果:</span></span>
<span class="line"><span>- 这 3 分钟的订单可能丢失</span></span>
<span class="line"><span>- 用户已经收到的&quot;创建成功&quot;反馈,异地查不到对应订单</span></span>
<span class="line"><span>- 需要业务侧的补偿、对账、人工处理</span></span></code></pre></div><p><strong>RPO 不是数字游戏,是实实在在的业务损失</strong>——3 分钟数据丢失对支付系统可能意味着数百笔交易要人工对账。</p><p>业务对数据敏感时,要用更严格的同步方式:</p><ul><li>半同步复制 — 主库等至少一个从库确认才提交</li><li>同步复制 — 主库等所有副本都确认</li><li>强一致协议(Raft/Paxos)— 多数派确认</li></ul><p>代价是写入延迟和性能下降——选择哪种取决于业务对一致性的真实需求。</p><h2 id="四、同城双活" tabindex="-1">四、同城双活 <a class="header-anchor" href="#四、同城双活" aria-label="Permalink to &quot;四、同城双活&quot;">​</a></h2><p><strong>同城双活</strong>:同一城市的两个机房<strong>同时承载业务</strong>。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20GLB%5B%22%E5%85%A8%E5%B1%80%E5%85%A5%E5%8F%A3%3Cbr%2F%3E(GSLB%2FDNS)%22%5D%0A%20%20subgraph%20%E5%90%8C%E5%9F%8E%E6%9C%BA%E6%88%BF%20A%0A%20%20%20%20A_App%5B%22%E5%BA%94%E7%94%A8%E9%9B%86%E7%BE%A4%22%5D%0A%20%20%20%20A_DB%5B(%22%E6%95%B0%E6%8D%AE%E5%BA%93%22)%5D%0A%20%20end%0A%20%20subgraph%20%E5%90%8C%E5%9F%8E%E6%9C%BA%E6%88%BF%20B%0A%20%20%20%20B_App%5B%22%E5%BA%94%E7%94%A8%E9%9B%86%E7%BE%A4%22%5D%0A%20%20%20%20B_DB%5B(%22%E6%95%B0%E6%8D%AE%E5%BA%93%22)%5D%0A%20%20end%0A%0A%20%20User%20--%3E%20GLB%0A%20%20GLB%20--%3E%20A_App%0A%20%20GLB%20--%3E%20B_App%0A%20%20A_DB%20%3C--%3E%7C%22%E5%90%8C%E6%AD%A5%E5%A4%8D%E5%88%B6%22%7C%20B_DB%0A"></div><h3 id="同城双活的特点" tabindex="-1">同城双活的特点 <a class="header-anchor" href="#同城双活的特点" aria-label="Permalink to &quot;同城双活的特点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>说明</th></tr></thead><tbody><tr><td>距离</td><td>同城内通常几十公里</td></tr><tr><td>网络延迟</td><td>1-3ms</td></tr><tr><td>同步方式</td><td>可以做同步或半同步复制</td></tr><tr><td>故障覆盖</td><td>单机房故障、机房网络设备故障、局部停电</td></tr><tr><td>切换时间</td><td>秒级到分钟级</td></tr><tr><td>数据丢失</td><td>接近零</td></tr></tbody></table><h3 id="同城双活解决什么问题" tabindex="-1">同城双活解决什么问题 <a class="header-anchor" href="#同城双活解决什么问题" aria-label="Permalink to &quot;同城双活解决什么问题&quot;">​</a></h3><ul><li>单机房硬件故障</li><li>机房网络中断</li><li>机房供电故障</li><li>机房空调失效</li><li>单机房整体维护</li></ul><p><strong>两边平时都接流量,故障时一边接管全部流量,不需要从冷启动拉起</strong>——切换时间远短于异地备。</p><h3 id="同城双活的难点-数据双活" tabindex="-1">同城双活的难点:数据双活 <a class="header-anchor" href="#同城双活的难点-数据双活" aria-label="Permalink to &quot;同城双活的难点:数据双活&quot;">​</a></h3><p><strong>读多写少的系统比较容易做双活</strong>——两边都能查询,写入集中在某一机房就够了。</p><p><strong>强一致写入的双活就要看&quot;写入归属&quot;怎么设计</strong>——两边同时写同一份数据必然碰到冲突:</p><table tabindex="0"><thead><tr><th>写入策略</th><th>含义</th><th>难点</th></tr></thead><tbody><tr><td>单写双读</td><td>写只在一个机房,两边都能读</td><td>写入机房故障时仍需切换</td></tr><tr><td>双写 + 同步复制</td><td>两边都能写,通过同步复制保证一致</td><td>跨机房同步延迟,性能下降</td></tr><tr><td>双写 + 分片</td><td>数据分片,每片有归属机房</td><td>工程复杂,跨片操作受限</td></tr><tr><td>双写 + 冲突解决</td><td>通过 CRDT、最后写入获胜等机制</td><td>业务侧要适应</td></tr></tbody></table><p>实际生产中真正做&quot;全部双写&quot;的系统很少,大部分双活是 <strong>&quot;读双活 + 单点写&quot;</strong>——两边都接读流量,写流量通过路由集中到某一边。</p><h2 id="五、异地双活" tabindex="-1">五、异地双活 <a class="header-anchor" href="#五、异地双活" aria-label="Permalink to &quot;五、异地双活&quot;">​</a></h2><p><strong>异地双活</strong>:不同城市或不同区域同时承载业务。</p><h3 id="异地双活解决什么问题" tabindex="-1">异地双活解决什么问题 <a class="header-anchor" href="#异地双活解决什么问题" aria-label="Permalink to &quot;异地双活解决什么问题&quot;">​</a></h3><ul><li>城市级灾难(地震、洪水、大规模停电)</li><li>区域级故障(运营商网络故障覆盖整个城市)</li><li>国家级监管要求(某些行业要求数据不能跨境)</li><li>用户就近接入(全球业务,降低延迟)</li></ul><h3 id="异地双活的难点" tabindex="-1">异地双活的难点 <a class="header-anchor" href="#异地双活的难点" aria-label="Permalink to &quot;异地双活的难点&quot;">​</a></h3><p>异地双活的难度远高于同城双活:</p><table tabindex="0"><thead><tr><th>难点</th><th>表现</th></tr></thead><tbody><tr><td>跨地域延迟</td><td>几十毫秒到 100ms+,同步操作变得困难</td></tr><tr><td>数据一致性</td><td>强同步性能不可接受,只能异步 + 业务补偿</td></tr><tr><td>网络成本</td><td>跨区域专线昂贵</td></tr><tr><td>运维复杂度</td><td>双倍的环境,部署、监控、变更都要协调</td></tr><tr><td>切换协调</td><td>多个组件同时切换的协调难度极大</td></tr></tbody></table><h3 id="单元化-异地双活的现实方案" tabindex="-1">单元化:异地双活的现实方案 <a class="header-anchor" href="#单元化-异地双活的现实方案" aria-label="Permalink to &quot;单元化:异地双活的现实方案&quot;">​</a></h3><p>真正&quot;任意请求打到任意区域&quot;的异地双活极少。<strong>更常见的是按某种维度分流(单元化)</strong>:</p><table tabindex="0"><thead><tr><th>分流维度</th><th>工作方式</th></tr></thead><tbody><tr><td>按地域</td><td>华东用户主要访问华东机房,华北用户主要访问华北机房</td></tr><tr><td>按用户 ID 哈希</td><td>用户固定归属某一区域,数据写入归属区域</td></tr><tr><td>按业务单元</td><td>不同业务在不同区域,业务间通过 API 互相调用</td></tr><tr><td>按时间</td><td>不同时段流量切到不同区域(主要用于切流演练)</td></tr></tbody></table><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User1%5B%22%E5%8C%97%E4%BA%AC%E7%94%A8%E6%88%B7%22%5D%0A%20%20User2%5B%22%E4%B8%8A%E6%B5%B7%E7%94%A8%E6%88%B7%22%5D%0A%20%20GLB%5B%22%E5%85%A8%E5%B1%80%E8%B0%83%E5%BA%A6%22%5D%0A%20%20subgraph%20%E5%8D%8E%E5%8C%97%E6%9C%BA%E6%88%BF%0A%20%20%20%20BJ_App%5B%22%E5%BA%94%E7%94%A8%22%5D%0A%20%20%20%20BJ_DB%5B(%22%E6%95%B0%E6%8D%AE%E5%BA%93%22)%5D%0A%20%20end%0A%20%20subgraph%20%E5%8D%8E%E4%B8%9C%E6%9C%BA%E6%88%BF%0A%20%20%20%20SH_App%5B%22%E5%BA%94%E7%94%A8%22%5D%0A%20%20%20%20SH_DB%5B(%22%E6%95%B0%E6%8D%AE%E5%BA%93%22)%5D%0A%20%20end%0A%0A%20%20User1%20--%3E%20GLB%0A%20%20User2%20--%3E%20GLB%0A%20%20GLB%20--%3E%7C%22%E5%8C%97%E4%BA%AC%E7%94%A8%E6%88%B7%E8%B7%AF%E7%94%B1%22%7C%20BJ_App%0A%20%20GLB%20--%3E%7C%22%E4%B8%8A%E6%B5%B7%E7%94%A8%E6%88%B7%E8%B7%AF%E7%94%B1%22%7C%20SH_App%0A%20%20BJ_DB%20%3C--%3E%7C%22%E5%8F%8C%E5%90%91%E5%90%8C%E6%AD%A5%3Cbr%2F%3E(%E5%90%84%E8%87%AA%E5%BD%92%E5%B1%9E%E7%9A%84%E6%95%B0%E6%8D%AE)%22%7C%20SH_DB%0A"></div><p><strong>单元化的核心思想</strong>:让每个用户的写入都在自己归属的单元完成,避免跨单元写冲突。</p><h3 id="用户归属切换的复杂度" tabindex="-1">用户归属切换的复杂度 <a class="header-anchor" href="#用户归属切换的复杂度" aria-label="Permalink to &quot;用户归属切换的复杂度&quot;">​</a></h3><p>单元化的代价是<strong>用户归属一旦需要变化</strong>(用户搬家、业务迁移、灾备切换),涉及的状态同步极其复杂:</p><ul><li>登录态 — 跨单元 session 不通,需要重新登录</li><li>缓存 — 用户相关的缓存在哪个单元?</li><li>订单状态 — 进行中的订单怎么迁移?</li><li>消息消费位移 — Kafka consumer offset 是单元独立的</li><li>第三方依赖 — 支付、短信等回调地址需要切换</li></ul><p><strong>单元归属切换本身就是个复杂工程</strong>,不是 DNS 切一下就完事的。</p><h2 id="六、两地三中心" tabindex="-1">六、两地三中心 <a class="header-anchor" href="#六、两地三中心" aria-label="Permalink to &quot;六、两地三中心&quot;">​</a></h2><p><strong>两地三中心</strong>是国内传统企业(尤其金融、电信、政务)最常见的容灾形态:</p><p><img src="`+o+`" alt="两地三中心要区分有机房和可切换"></p><ul><li><strong>同城</strong>两个生产中心</li><li><strong>异地</strong>一个灾备中心</li></ul><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20subgraph%20%E5%90%8C%E5%9F%8E%0A%20%20%20%20A%5B(%22%E7%94%9F%E4%BA%A7%E4%B8%AD%E5%BF%83%20A%3Cbr%2F%3E%E4%B8%BB%E4%B8%9A%E5%8A%A1%22)%5D%0A%20%20%20%20B%5B(%22%E7%81%BE%E5%A4%87%E4%B8%AD%E5%BF%83%20B%3Cbr%2F%3E%E5%90%8C%E6%AD%A5%E5%A4%8D%E5%88%B6%2C%E5%8F%AF%E6%8E%A5%E7%AE%A1%22)%5D%0A%20%20end%0A%20%20subgraph%20%E5%BC%82%E5%9C%B0%0A%20%20%20%20C%5B(%22%E5%BC%82%E5%9C%B0%E7%81%BE%E5%A4%87%E4%B8%AD%E5%BF%83%3Cbr%2F%3E%E5%BC%82%E6%AD%A5%E5%A4%8D%E5%88%B6%22)%5D%0A%20%20end%0A%0A%20%20A%20%3C--%3E%7C%22%E5%90%8C%E6%AD%A5%2F%E5%8D%8A%E5%90%8C%E6%AD%A5%22%7C%20B%0A%20%20A%20-.-%3E%7C%22%E5%BC%82%E6%AD%A5%22%7C%20C%0A%20%20B%20-.-%3E%7C%22%E5%BC%82%E6%AD%A5%22%7C%20C%0A"></div><h3 id="各中心的角色" tabindex="-1">各中心的角色 <a class="header-anchor" href="#各中心的角色" aria-label="Permalink to &quot;各中心的角色&quot;">​</a></h3><table tabindex="0"><thead><tr><th>中心</th><th>职责</th></tr></thead><tbody><tr><td>同城生产中心</td><td>承载主要业务流量</td></tr><tr><td>同城灾备中心</td><td>低延迟接管,处理本地中心故障</td></tr><tr><td>异地灾备中心</td><td>处理城市级灾难</td></tr></tbody></table><h3 id="各中心的同步策略" tabindex="-1">各中心的同步策略 <a class="header-anchor" href="#各中心的同步策略" aria-label="Permalink to &quot;各中心的同步策略&quot;">​</a></h3><ul><li><strong>同城两中心</strong>:距离近,可以做同步或半同步复制(数据几乎不丢)</li><li><strong>异地中心</strong>:距离远,一般做异步复制(可能丢少量数据)</li></ul><p>这样组合下来:</p><ul><li>本地快速切换(应对机房级故障)</li><li>异地兜底(应对城市级灾难)</li></ul><h3 id="有机房-和-可切换-是两回事" tabindex="-1">&quot;有机房&quot;和&quot;可切换&quot;是两回事 <a class="header-anchor" href="#有机房-和-可切换-是两回事" aria-label="Permalink to &quot;&quot;有机房&quot;和&quot;可切换&quot;是两回事&quot;">​</a></h3><p><strong>异地灾备最大的认知陷阱</strong>:</p><ul><li>异地机房租了 ✓</li><li>异地机器装了 ✓</li><li>异地数据同步了 ✓</li><li>异地业务从没真正切过 ✗</li></ul><p>这种状态下,<strong>异地中心只是&quot;有资源&quot;,不是&quot;可靠容灾&quot;</strong>——真出事时,可能切不过去,或切过去后业务跑不通。</p><p>完整的可靠容灾要持续投入:</p><table tabindex="0"><thead><tr><th>持续工作</th><th>频率</th></tr></thead><tbody><tr><td>数据同步监控</td><td>实时</td></tr><tr><td>配置同步</td><td>每次变更</td></tr><tr><td>应用部署同步</td><td>每次发布</td></tr><tr><td>完整切换演练</td><td>每年至少 1 次</td></tr><tr><td>部分切换演练</td><td>每季度</td></tr><tr><td>灾备站点扩容</td><td>跟生产一起</td></tr><tr><td>灾备人员培训</td><td>每年</td></tr></tbody></table><p><strong>异地灾备的运营成本可能比一个普通业务集群还高</strong>——但这是真正能用的容灾必须付的代价。</p><h2 id="七、多活架构的风险" tabindex="-1">七、多活架构的风险 <a class="header-anchor" href="#七、多活架构的风险" aria-label="Permalink to &quot;七、多活架构的风险&quot;">​</a></h2><p>多活听起来美好(故障无感、性能更好、容灾天然),但<strong>实际落地涉及系统的方方面面</strong>,每一处都可能成为新故障源。</p><h3 id="主要风险点" tabindex="-1">主要风险点 <a class="header-anchor" href="#主要风险点" aria-label="Permalink to &quot;主要风险点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>风险</th><th>表现</th></tr></thead><tbody><tr><td>写冲突</td><td>两个机房同时修改同一数据,合并时不知道以谁为准</td></tr><tr><td>缓存不一致</td><td>用户在不同机房看到不同状态</td></tr><tr><td>消息重复消费</td><td>两边都消费同一事件,业务被处理两次</td></tr><tr><td>定时任务重复</td><td>定时任务在多机房同时跑,发两次邮件、扣两次款</td></tr><tr><td>切换不完整</td><td>入口切走但后端、数据库、消息队列还在旧链路</td></tr><tr><td>Session 跨域</td><td>用户在 A 机房登录,请求被路由到 B 机房,登录态失效</td></tr><tr><td>跨域调用延迟</td><td>单元内调用 ms 级,跨单元调用几十毫秒</td></tr><tr><td>数据回流</td><td>异地的数据要回流到主站做汇总分析</td></tr></tbody></table><h3 id="容灾演练-必须跑完整业务路径" tabindex="-1">容灾演练:必须跑完整业务路径 <a class="header-anchor" href="#容灾演练-必须跑完整业务路径" aria-label="Permalink to &quot;容灾演练:必须跑完整业务路径&quot;">​</a></h3><p><strong>容灾演练不是&quot;切个 DNS 看能不能 ping 通&quot;</strong>——必须跑完整业务路径:</p><ul><li>用户登录</li><li>商品查询</li><li>下单流程</li><li>支付流程</li><li>文件上传/下载</li><li>后台任务</li><li>报表导出</li><li>第三方回调</li></ul><p>每条主流程都要走一遍,验证切换后的新机房能正常工作。</p><h3 id="演练记录要写实际结果" tabindex="-1">演练记录要写实际结果 <a class="header-anchor" href="#演练记录要写实际结果" aria-label="Permalink to &quot;演练记录要写实际结果&quot;">​</a></h3><p>记录格式参考:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>演练时间:2026-06-01 02:00</span></span>
<span class="line"><span>演练范围:全量切到异地灾备中心</span></span>
<span class="line"><span>实际结果:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>02:00 - 触发切换</span></span>
<span class="line"><span>02:01 - 入口 DNS 切换完成</span></span>
<span class="line"><span>02:03 - 异地数据库提升为主</span></span>
<span class="line"><span>02:05 - 应用集群启动,健康检查通过</span></span>
<span class="line"><span>02:07 - 登录功能恢复 ✓</span></span>
<span class="line"><span>02:09 - 商品查询恢复 ✓</span></span>
<span class="line"><span>02:12 - 下单流程恢复 ✓</span></span>
<span class="line"><span>02:15 - 支付回调失败! 第三方支付的回调地址还指向原主站</span></span>
<span class="line"><span>02:18 - 手动修改支付回调配置</span></span>
<span class="line"><span>02:25 - 报表任务失败,异地的 Kafka consumer 没启动</span></span>
<span class="line"><span>02:30 - 启动 consumer,报表恢复</span></span>
<span class="line"><span>02:35 - 切回原主站</span></span>
<span class="line"><span></span></span>
<span class="line"><span>问题清单:</span></span>
<span class="line"><span>1. 支付回调地址未纳入切换流程</span></span>
<span class="line"><span>2. Kafka consumer 在异地需要手动启动</span></span>
<span class="line"><span>3. 应用启动后 5 分钟才完全 ready,需要优化健康检查</span></span></code></pre></div><p><strong>这种暴露问题的演练记录,远比&quot;演练成功&quot;四个字有价值</strong>——真正暴露问题、推动修复,才是演练的目的。</p><p>光说&quot;演练成功&quot;等于没演练,真出事时该踩的坑一个都少不了。</p><h2 id="八、容灾的成本-收益评估" tabindex="-1">八、容灾的成本-收益评估 <a class="header-anchor" href="#八、容灾的成本-收益评估" aria-label="Permalink to &quot;八、容灾的成本-收益评估&quot;">​</a></h2><p>不是所有业务都需要高规格容灾。投资容灾前,要做合理的成本-收益评估:</p><table tabindex="0"><thead><tr><th>业务类型</th><th>不可用 1 小时的损失</th><th>合理容灾投入</th></tr></thead><tbody><tr><td>个人博客</td><td>几乎零</td><td>异地备份足矣</td></tr><tr><td>内部工具</td><td>影响员工效率</td><td>异地冷备</td></tr><tr><td>一般电商</td><td>数十万</td><td>同城主备 + 异地异步备</td></tr><tr><td>大型电商</td><td>数百万到千万</td><td>同城双活 + 异地热备</td></tr><tr><td>金融核心</td><td>数千万+ + 合规处罚</td><td>异地多活 + 强一致</td></tr><tr><td>关键基础设施</td><td>难以估量</td><td>多区域多活 + 持续演练</td></tr></tbody></table><p><strong>容灾投入的核心问题不是&quot;我能做到多强&quot;,而是&quot;我需要做到多强&quot;</strong>。盲目追求&quot;零 RTO 零 RPO&quot;会让成本失控,反而拖垮整个系统经济性。</p><h3 id="容灾投入的渐进路径" tabindex="-1">容灾投入的渐进路径 <a class="header-anchor" href="#容灾投入的渐进路径" aria-label="Permalink to &quot;容灾投入的渐进路径&quot;">​</a></h3><p>合理的容灾投入是<strong>随业务增长渐进的</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段 1:本地备份 + 监控告警           (启动期)</span></span>
<span class="line"><span>阶段 2:数据库主从 + 异地备份            (成长期)</span></span>
<span class="line"><span>阶段 3:同城主备 + 异地异步备             (扩展期)</span></span>
<span class="line"><span>阶段 4:同城双活 + 异地热备                (成熟期)</span></span>
<span class="line"><span>阶段 5:异地多活 + 完整演练体系            (大型化)</span></span></code></pre></div><p>每一步都解决具体的容灾需求,<strong>不要跳过中间阶段直接上多活</strong>——多活的工程复杂度极高,小规模团队根本无法运维。</p><h3 id="容灾的真正成本不是机器钱" tabindex="-1">容灾的真正成本不是机器钱 <a class="header-anchor" href="#容灾的真正成本不是机器钱" aria-label="Permalink to &quot;容灾的真正成本不是机器钱&quot;">​</a></h3><table tabindex="0"><thead><tr><th>成本类型</th><th>内容</th></tr></thead><tbody><tr><td>硬件</td><td>异地机房、机器、网络专线</td></tr><tr><td>运维</td><td>异地的部署、监控、变更同步</td></tr><tr><td>人力</td><td>容灾团队、演练、应急响应</td></tr><tr><td>流程</td><td>容灾流程的设计、文档、培训</td></tr><tr><td>业务适配</td><td>应用层为容灾做的改造</td></tr><tr><td>演练时间</td><td>定期演练对生产的影响</td></tr><tr><td>持续优化</td><td>业务变化时容灾方案要跟着变</td></tr></tbody></table><p>机器和带宽只是冰山一角,<strong>长期运营成本才是大头</strong>。这就是为什么&quot;看起来便宜的容灾方案&quot;在实际运营几年后,总成本可能超过预期数倍。</p>`,126)])])}const q=a(i,[["render",p]]);export{g as __pageData,q as default};
